  7	import {
  8	  ButtonBar,
  9	  formSettings,
 10	  useYupValidationResolver,
 11	  TextInputWithFieldRequirements,
 12	} from '@odf/shared';
 13	import { fieldRequirementsTranslations } from '@odf/shared/constants';
 14	import { CommonModalProps } from '@odf/shared/modals';
 15	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 16	import validationRegEx from '@odf/shared/utils/validation';
 17	import { useForm, FieldValues, Control } from 'react-hook-form';
 18	import * as Yup from 'yup';
 19	import {
 20	  Button,
 21	  ButtonVariant,
 22	  Flex,
 23	  FlexItem,
 24	  Form,
 25	  Modal,
 26	  ModalVariant,
 27	} from '@patternfly/react-core';
 28	
 29	const FILESYSTEM_NAME_MAX_LENGTH = 63;
 30	const FILESYSTEM_NAME_MIN_LENGTH = 3;
 31	
 32	const AddRemoteFileSystemModal: React.FC<
 33	  CommonModalProps<{ remoteClusterName: string }>
 34	> = ({ closeModal, isOpen, extraProps: { remoteClusterName } }) => {
 35	  const { t } = useCustomTranslation();
 36	  const [inProgress, setInProgress] = React.useState(false);
 37	  const [error, setError] = React.useState(null);
 38	
 39	  const existingFileSystemNames = useExistingFileSystemNames();
 40	
 41	  const { formSchema, fieldRequirements } = React.useMemo(() => {
 42	    const fileSystemNameFieldRequirements = {
 43	      maxChars: fieldRequirementsTranslations.maxChars(
 44	        t,
 45	        FILESYSTEM_NAME_MAX_LENGTH
 46	      ),
 47	      minChars: fieldRequirementsTranslations.minChars(
 48	        t,
 49	        FILESYSTEM_NAME_MIN_LENGTH
 50	      ),
 51	      startAndEndName: fieldRequirementsTranslations.startAndEndName(t),
 52	      alphaNumericPeriodAdnHyphen:
 53	        fieldRequirementsTranslations.alphaNumericPeriodAdnHyphen(t),
 54	      mustBeUnique: t('Name must be unique'),
 55	    };
 56	
 57	    const formSchema = Yup.object({
 58	      remoteFileSystemName: Yup.string()
 59	        .required(t('File system name is required'))
 60	        .max(
 61	          FILESYSTEM_NAME_MAX_LENGTH,
 62	          fileSystemNameFieldRequirements.maxChars
 63	        )
 64	        .min(
 65	          FILESYSTEM_NAME_MIN_LENGTH,
 66	          fileSystemNameFieldRequirements.minChars
 67	        )
 68	        .matches(
 69	          validationRegEx.startAndEndsWithAlphanumerics,
 70	          fileSystemNameFieldRequirements.startAndEndName
 71	        )
 72	        .matches(
 73	          validationRegEx.alphaNumericsPeriodsHyphensNonConsecutive,
 74	          fileSystemNameFieldRequirements.alphaNumericPeriodAdnHyphen
 75	        )
 76	        .test(
 77	          'unique-filesystem-name',
 78	          fileSystemNameFieldRequirements.mustBeUnique,
 79	          createUniquenessValidator(existingFileSystemNames)
 80	        )
 81	        .transform((value: string) => (!!value ? value : '')),
 82	    });
 83	
 84	    return {
 85	      formSchema,
 86	      fieldRequirements: {
 87	        remoteFileSystemName: Object.values(fileSystemNameFieldRequirements),
 88	      },
 89	    };
 90	  }, [t, existingFileSystemNames]);
 91	
 92	  const resolver = useYupValidationResolver(formSchema) as any;
 93	
 94	  const { control, watch, handleSubmit } = useForm({
 95	    ...formSettings,
 96	    resolver,
 97	    defaultValues: {
 98	      remoteFileSystemName: '',
 99	    },
100	  });
101	
102	  const remoteFileSystemName = watch('remoteFileSystemName');
103	
104	  const handleCreate = handleSubmit(async () => {
105	    setInProgress(true);
106	    const fileSystemPromise = createFileSystem(
107	      remoteClusterName,
108	      remoteFileSystemName
109	    );
110	    try {
111	      await fileSystemPromise();
112	      closeModal();
113	    } catch (err) {
114	      setError(err);
115	    } finally {
116	      setInProgress(false);
117	    }
118	  });
119	  return (
120	    <Modal
121	      title={t('Add Remote FileSystem')}
122	      variant={ModalVariant.medium}
123	      isOpen={isOpen}
124	      onClose={closeModal}
125	      actions={[
126	        <ButtonBar inProgress={inProgress} errorMessage={error?.message}>
127	          <Flex display={{ default: 'inlineFlex' }}>
128	            <FlexItem>
129	              <Button
130	                variant={ButtonVariant.primary}
131	                onClick={handleCreate}
132	                isDisabled={!remoteFileSystemName || !!error}
133	                isLoading={inProgress}
134	              >
135	                {t('Add')}
136	              </Button>
137	            </FlexItem>
138	            <FlexItem>
139	              <Button variant={ButtonVariant.secondary} onClick={closeModal}>
140	                {t('Cancel')}
141	              </Button>
142	            </FlexItem>
143	          </Flex>
144	        </ButtonBar>,
145	      ]}
146	    >
147	      <Form>
148	        <TextInputWithFieldRequirements
149	          control={control as Control<FieldValues>}
150	          fieldRequirements={fieldRequirements.remoteFileSystemName}
151	          popoverProps={{
152	            headerContent: t('File system name requirements'),
153	            footerContent: `${t('Example')}: my-filesystem`,
154	          }}
155	          formGroupProps={{
156	            label: t('Remote filesystem name'),
157	            fieldId: 'remote-file-system-name',
158	            isRequired: true,
159	          }}
160	          textInputProps={{
161	            id: 'remoteFileSystemName',
162	            name: 'remoteFileSystemName',
163	            type: 'text',
164	            'data-test': 'remote-file-system-name',
165	          }}
166	        />
167	      </Form>
168	    </Modal>
169	  );
170	};
171	
172	export default AddRemoteFileSystemModal;

